/* thumbnail-loader.compat.min.js
 * FINAL – DistributionHub Safe Mode
 * - 모든 프론트 공용
 * - distributionhub 페이지만 append-only 안전 렌더
 * - No item DOM 생성 제거
 */
(function () {
  "use strict";

  var PAGEKEY_ATTR = "data-psom-key";
  var FEED_ENDPOINT = "/.netlify/functions/feed";
  var isDistribution =
    window.IGDC_PAGE && window.IGDC_PAGE.pageId === "distributionhub";

  function getHosts() {
    try {
      return Array.prototype.slice.call(
        document.querySelectorAll("[" + PAGEKEY_ATTR + "]")
      );
    } catch (e) {
      return [];
    }
  }

  function safeText(s) {
    return (s == null ? "" : String(s))
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");
  }

  function guessLang() {
    try {
      var l = (document.documentElement.getAttribute("lang") || "").trim();
      if (l) return l;
    } catch (e) {}
    return "ko";
  }

  function mapItem(x) {
    if (!x) return null;
    return {
      title: safeText(x.title || x.name || x.label || ""),
      href: x.href || x.url || "#",
      img: x.img || x.image || x.thumbnail || "",
      desc: safeText(x.desc || x.description || x.category || "")
    };
  }

  function buildHTML(items) {
    return items
      .map(function (it) {
        var s = mapItem(it);
        if (!s) return "";
        var img = s.img
          ? '<img loading="lazy" decoding="async" src="' +
            s.img +
            '" alt=""/>'
          : "";
        var dsc = s.desc ? '<div class="d">' + s.desc + "</div>" : "";
        return (
          '<a class="thumb-card" href="' +
          s.href +
          '" target="_blank" rel="noopener noreferrer">' +
          img +
          '<div class="t">' +
          s.title +
          "</div>" +
          dsc +
          "</a>"
        );
      })
      .join("");
  }

  function renderInto(host, items) {
    if (!host) return;
    if (!Array.isArray(items) || items.length === 0) return;

    // 유통허브: append-only + 1회 렌더
    if (isDistribution) {
      if (host.dataset.mounted === "1") return;
      host.dataset.mounted = "1";

      host
        .querySelectorAll(".thumb-empty,.no-item,.empty")
        .forEach(function (el) {
          el.remove();
        });

      host.insertAdjacentHTML("beforeend", buildHTML(items));
      return;
    }

    // 다른 페이지: 기존 방식 유지
    host.innerHTML = buildHTML(items);
  }

  function normalizeJson(json) {
    if (!json) return [];
    if (Array.isArray(json)) return json;
    if (Array.isArray(json.items)) return json.items;
    if (json.data && Array.isArray(json.data)) return json.data;
    if (json.data && Array.isArray(json.data.items)) return json.data.items;
    return [];
  }

  function fetchFeed(pageKey) {
    var url =
      FEED_ENDPOINT +
      "?page=" +
      encodeURIComponent(pageKey) +
      "&lang=" +
      encodeURIComponent(guessLang());
    try {
      if (
        window.IGDC_CORE &&
        typeof window.IGDC_CORE.country === "function"
      ) {
        url += "&country=" + encodeURIComponent(window.IGDC_CORE.country());
      }
    } catch (e) {}
    return fetch(url, { cache: "no-store", credentials: "omit" })
      .then(function (r) {
        if (!r.ok) throw new Error("HTTP_" + r.status);
        return r.json();
      })
      .then(normalizeJson);
  }

  function fetchFallback() {
    return fetch("/assets/hero/psom.json", { credentials: "omit" })
      .then(function (r) {
        if (!r.ok) throw new Error("HTTP_" + r.status);
        return r.json();
      })
      .then(normalizeJson);
  }

  function filterByPage(items, pageKey) {
    var k = (pageKey || "").toLowerCase();
    return (items || []).filter(function (it) {
      var p = (it.page || it.pageKey || it.key || "").toLowerCase();
      return p === k;
    });
  }

  var cache = Object.create(null);

  function loadForHost(host) {
    var key = (host.getAttribute(PAGEKEY_ATTR) || "").trim();
    if (!key) return;

    if (!cache[key]) {
      cache[key] = fetchFeed(key).catch(function () {
        return fetchFallback().then(function (all) {
          return filterByPage(all, key);
        });
      });
    }

    cache[key]
      .then(function (items) {
        renderInto(host, items);
      })
      .catch(function () {});
  }

  function init() {
    var hosts = getHosts();
    if (!hosts.length) return;
    hosts.forEach(loadForHost);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }

  window.__THUMB_VERSION__ = "distribution-safe-final";
})();
